import unittest
from app.validation import validate_item, ValidationError

class TestValidation(unittest.TestCase):

    def test_validate_item_success(self):
        """Test that validate_item passes with a valid item."""
        validate_item({'name': 'Test Item', 'price': 10.0})

    def test_validate_item_missing_name(self):
        """Test that validate_item raises an error if name is missing."""
        with self.assertRaises(ValidationError):
            validate_item({'price': 10.0})

    def test_validate_item_missing_price(self):
        """Test that validate_item raises an error if price is missing."""
        with self.assertRaises(ValidationError):
            validate_item({'name': 'Test Item'})

if __name__ == '__main__':
    unittest.main()

import unittest
from unittest.mock import patch
from app.order_processing import calculate_total, process_order, OrderProcessingError
from app.validation import ValidationError

class TestOrderProcessing(unittest.TestCase):

    def test_calculate_total_success(self):
        """Test that calculate_total calculates the total correctly."""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2', 'price': 20.5}
        ]
        self.assertAlmostEqual(calculate_total(items), 30.5)

    def test_calculate_total_missing_price(self):
        """Test that calculate_total raises an error if price is missing."""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2'}
        ]
        with self.assertRaises(OrderProcessingError):
            calculate_total(items)

    def test_calculate_total_invalid_price(self):
        """Test that calculate_total raises an error if price is invalid."""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2', 'price': -5.0}
        ]
        with self.assertRaises(OrderProcessingError):
            calculate_total(items)

    @patch('app.order_processing.validate_item')
    def test_process_order_success(self, mock_validate_item):
        """Test that process_order processes an order successfully."""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2', 'price': 20.0}
        ]
        result = process_order('ORD-001', items)
        self.assertEqual(result, {
            'order_id': 'ORD-001',
            'total': 30.0,
            'status': 'processed'
        })
        mock_validate_item.assert_any_call(items[0])
        mock_validate_item.assert_any_call(items[1])

    @patch('app.order_processing.validate_item')
    def test_process_order_validation_error(self, mock_validate_item):
        """Test that process_order handles validation errors."""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2'}
        ]
        mock_validate_item.side_effect = ValidationError("Item is missing the 'price' key.")
        with self.assertRaises(ValidationError):
            process_order('ORD-001', items)

if __name__ == '__main__':
    unittest.main()

